package.sql:

  DECLARE
      v_broker_aetitle                VARCHAR2(32)   := '';
      v_order_control_id              VARCHAR2(16)   := '';
      v_event_type                    VARCHAR2(32)   := @EVENT_TYPE;
      v_character_set                 VARCHAR2(32)   := @CHARACTER_SET;
      v_scheduled_aetitle             VARCHAR2(16)   := @SCHEDULED_AETITLE;
      v_scheduled_dttm                VARCHAR2(32)   := @SCHEDULED_DTTM;
      v_scheduled_modality            VARCHAR2(8)    := @SCHEDULED_MODALITY;
      v_scheduled_station             VARCHAR2(32)   := @SCHEDULED_STATION;
      v_scheduled_location            VARCHAR2(32)   := @SCHEDULED_LOCATION;
      v_scheduled_proc_id             VARCHAR2(32)   := @SCHEDULED_PROC_ID;         -- 10
      v_scheduled_proc_desc           VARCHAR2(64)   := @SCHEDULED_PROC_DESC;
      v_scheduled_action_codes        VARCHAR2(256)  := @SCHEDULED_ACTION_CODES;
      v_scheduled_proc_status         VARCHAR2(32)   := @SCHEDULED_PROC_STATUS;
      v_premedication                 VARCHAR2(32)   := @PREMEDICATION;
      v_contrast_agent                VARCHAR2(32)   := @CONTRAST_AGENT;
      v_requested_proc_id             VARCHAR2(32)   := @REQUESTED_PROC_ID;
      v_requested_proc_desc           VARCHAR2(64)   := @REQUESTED_PROC_DESC;
      v_requested_proc_codes          VARCHAR2(256)  := @REQUESTED_PROC_CODES;
      v_requested_proc_priority       VARCHAR2(32)   := @REQUESTED_PROC_PRIORITY;
      v_requested_proc_reason         VARCHAR2(256)  := @REQUESTED_PROC_REASON;        -- 20
      v_requested_proc_comments       VARCHAR2(4000) := @REQUESTED_PROC_COMMENTS;
      v_study_instance_uid            VARCHAR2(64)   := @STUDY_INSTANCE_UID;
      v_proc_placer_order_no          VARCHAR2(32)   := @PROC_PLACER_ORDER_NO;
      v_proc_filler_order_no          VARCHAR2(32)   := @PROC_FILLER_ORDER_NO;
      v_accession_no                  VARCHAR2(32)   := @ACCESSION_NO;
      v_attend_doctor                 VARCHAR2(32)   := @ATTEND_DOCTOR;
      v_perform_doctor                VARCHAR2(32)   := @PERFORM_DOCTOR;
      v_consult_doctor                VARCHAR2(32)   := @CONSULT_DOCTOR;
      v_request_doctor                VARCHAR2(32)   := @REQUEST_DOCTOR;
      v_refer_doctor                  VARCHAR2(32)   := @REFER_DOCTOR;         -- 30
      v_request_department            VARCHAR2(32)   := @REQUEST_DEPARTMENT;
      v_imaging_request_reason        VARCHAR2(64)   := @IMAGING_REQUEST_REASON;
      v_imaging_request_comments      VARCHAR2(4000) := @IMAGING_REQUEST_COMMENTS;
      v_imaging_request_dttm          VARCHAR2(14)   := @IMAGING_REQUEST_DTTM;
      v_isr_placer_order_no           VARCHAR2(32)   := @ISR_PLACER_ORDER_NO;
      v_isr_filler_order_no           VARCHAR2(32)   := @ISR_FILLER_ORDER_NO;
      v_admission_id                  VARCHAR2(32)   := @ADMISSION_ID;
      v_patient_transport             VARCHAR2(32)   := @PATIENT_TRANSPORT;
      v_patient_location              VARCHAR2(32)   := @PATIENT_LOCATION;
      v_patient_residency             VARCHAR2(80)   := @PATIENT_RESIDENCY;         -- 40
      v_patient_name                  VARCHAR2(64)   := @PATIENT_NAME;
      v_patient_id                    VARCHAR2(64)   := @PATIENT_ID;
      v_other_patient_name            VARCHAR2(64)   := @OTHER_PATIENT_NAME;
      v_other_patient_id              VARCHAR2(64)   := @OTHER_PATIENT_ID;
      v_patient_birth_dttm            VARCHAR2(8)    := @PATIENT_BIRTH_DATE;
      v_patient_sex                   CHAR(1)        := @PATIENT_SEX;
      v_patient_weight                VARCHAR2(16)   := @PATIENT_WEIGHT;
      v_patient_size                  VARCHAR2(16)   := @PATIENT_SIZE;
      v_patient_state                 VARCHAR2(256)  := @PATIENT_STATE;
      v_confidentiality               VARCHAR2(256)  := @CONFIDENTIALITY;        -- 50
      v_pregnancy_status              VARCHAR2(256)  := @PREGNANCY_STATUS;
      v_medical_alerts                VARCHAR2(256)  := @MEDICAL_ALERTS;
      v_contrast_allergies            VARCHAR2(256)  := @CONTRAST_ALLERGIES;
      v_special_needs                 VARCHAR2(32)   := @SPECIAL_NEEDS;
      v_specialty                     VARCHAR2(32)   := @SPECIALTY;
      v_diagnosis                     VARCHAR2(2048) := @DIAGNOSIS;
      v_admit_dttm                    VARCHAR2(32)   := @ADMIT_DTTM;
      v_register_dttm                 VARCHAR2(32)   := @REGISTER_DTTM;
      v_study_ssn                     VARCHAR2(64)   := @STUDY_SSN;
      v_insurance_code                VARCHAR2(64)   := @INSURANCE_CODE;         -- 60
      v_emergency                     VARCHAR2(8)    := @EMERGENCY;
      v_special_doctor                VARCHAR2(32)   := @SPECIAL_DOCTOR;         -- 62
      
      v_m_patient_id_issuer           VARCHAR2(32);
      v_m_last_name                   VARCHAR2(32);
      v_m_first_name                  VARCHAR2(32);
      v_m_middle_name                 VARCHAR2(32);
      v_m_prefix                      VARCHAR2(32);
      v_m_suffix                      VARCHAR2(32);
      v_m_race_code                   VARCHAR2(32);
      v_m_account_no                  VARCHAR2(32);         -- 70
      v_m_address                     VARCHAR2(128);
      v_m_order_entry_user_id         VARCHAR2(64);
      v_m_order_entry_location        VARCHAR2(512);
      v_m_order_callback_phone_no     VARCHAR2(512);
      v_m_req_proc_status             VARCHAR2(8);
      v_m_req_proc_code_scheme        VARCHAR2(32);
      v_m_req_proc_code_version       VARCHAR2(32);
      v_m_req_proc_code_meaning       VARCHAR2(256);
      v_m_req_proc_location           VARCHAR2(32);
      v_m_patient_arrange             VARCHAR2(32);         -- 80
      v_m_source_aetitle              VARCHAR2(16);
      v_m_broker_type                 VARCHAR2(16);         -- 82
  
  BEGIN
      
      SP_FILTER.MWL_TO_MWL(
              v_broker_aetitle, 
              v_order_control_id,
              v_event_type,
              v_character_set,
              v_scheduled_aetitle,
              v_scheduled_dttm,
              v_scheduled_modality,
              v_scheduled_station,
              v_scheduled_location,
              v_scheduled_proc_id,        -- 10
              v_scheduled_proc_desc,
              v_scheduled_action_codes,
              v_scheduled_proc_status,
              v_premedication,
              v_contrast_agent,
              v_requested_proc_id,
              v_requested_proc_desc,
              v_requested_proc_codes,
              v_requested_proc_priority,
              v_requested_proc_reason,    -- 20
              v_requested_proc_comments,
              v_study_instance_uid,
              v_proc_placer_order_no,
              v_proc_filler_order_no,
              v_accession_no,
              v_attend_doctor,
              v_perform_doctor,
              v_consult_doctor,
              v_request_doctor,
              v_refer_doctor,             -- 30
              v_request_department,
              v_imaging_request_reason,
              v_imaging_request_comments,
              v_imaging_request_dttm,
              v_isr_placer_order_no,
              v_isr_filler_order_no,
              v_admission_id,
              v_patient_transport,
              v_patient_location,
              v_patient_residency,        -- 40
              v_patient_name,
              v_patient_id,
              v_other_patient_name,
              v_other_patient_id,
              v_patient_birth_dttm,
              v_patient_sex,
              v_patient_weight,
              v_patient_size,
              v_patient_state,
              v_confidentiality,          -- 50
              v_pregnancy_status,
              v_medical_alerts,
              v_contrast_allergies,
              v_special_needs,
              v_specialty,
              v_diagnosis,
              v_admit_dttm,
              v_register_dttm,
              v_study_ssn,
              v_insurance_code,           -- 60
              v_emergency,
              v_special_doctor,           -- 62
              
              v_m_patient_id_issuer,
              v_m_last_name,
              v_m_first_name,
              v_m_middle_name,
              v_m_prefix,
              v_m_suffix,
              v_m_race_code,
              v_m_account_no,             -- 70
              v_m_address,
              v_m_order_entry_user_id,
              v_m_order_entry_location,
              v_m_order_callback_phone_no,
              v_m_req_proc_status,
              v_m_req_proc_code_scheme,
              v_m_req_proc_code_version,
              v_m_req_proc_code_meaning,
              v_m_req_proc_location,
              v_m_patient_arrange,        -- 80
              v_m_source_aetitle,
              v_m_broker_type             -- 82
          );
      
      SP_MAPPER.PUT_MWL(
              v_event_type,
              v_order_control_id,
              v_character_set,
              v_scheduled_aetitle,
              v_scheduled_dttm,
              v_scheduled_modality,
              v_scheduled_station,
              v_scheduled_location,
              v_scheduled_proc_id,
              v_scheduled_proc_desc,      -- 10
              v_scheduled_action_codes,
              v_scheduled_proc_status,
              v_premedication,
              v_contrast_agent,
              v_requested_proc_id,
              v_requested_proc_desc,
              v_requested_proc_codes,
              v_requested_proc_priority,
              v_requested_proc_reason,
              v_requested_proc_comments,  -- 20
              v_study_instance_uid,
              v_proc_placer_order_no,
              v_proc_filler_order_no,
              v_accession_no,
              v_attend_doctor,
              v_perform_doctor,
              v_consult_doctor,
              v_request_doctor,
              v_refer_doctor,
              v_request_department,       -- 30
              v_imaging_request_reason,
              v_imaging_request_comments,
              v_imaging_request_dttm,
              v_isr_placer_order_no,
              v_isr_filler_order_no,
              v_admission_id,
              v_patient_transport,
              v_patient_location,
              v_patient_residency,
              v_patient_name,             -- 40
              v_patient_id,
              v_other_patient_name,
              v_other_patient_id,
              v_patient_birth_dttm,
              v_patient_sex,
              v_patient_weight,
              v_patient_size,
              v_patient_state,
              v_confidentiality,
              v_pregnancy_status,         -- 50
              v_medical_alerts,
              v_contrast_allergies,
              v_special_needs,
              v_specialty,
              v_diagnosis,
              v_admit_dttm,
              v_register_dttm, 
              v_study_ssn                 -- 58
          );
  END;

      
        DECLARE
            v_study_key                     NUMBER;
            v_msps_key                      NUMBER;
            v_insurancefee_key              NUMBER;
            
            v_broker_aetitle                VARCHAR2(32)   := '';
            v_order_control_id              VARCHAR2(16)   := '';
            v_event_type                    VARCHAR2(32)   := @EVENT_TYPE;
            v_character_set                 VARCHAR2(32)   := @CHARACTER_SET;
            v_scheduled_aetitle             VARCHAR2(16)   := @SCHEDULED_AETITLE;
            v_scheduled_dttm                VARCHAR2(32)   := @SCHEDULED_DTTM;
            v_scheduled_modality            VARCHAR2(8)    := @SCHEDULED_MODALITY;
            v_scheduled_station             VARCHAR2(32)   := @SCHEDULED_STATION;
            v_scheduled_location            VARCHAR2(32)   := @SCHEDULED_LOCATION;
            v_scheduled_proc_id             VARCHAR2(32)   := @SCHEDULED_PROC_ID;         -- 10
            v_scheduled_proc_desc           VARCHAR2(64)   := @SCHEDULED_PROC_DESC;
            v_scheduled_action_codes        VARCHAR2(256)  := @SCHEDULED_ACTION_CODES;
            v_scheduled_proc_status         VARCHAR2(32)   := @SCHEDULED_PROC_STATUS;
            v_premedication                 VARCHAR2(32)   := @PREMEDICATION;
            v_contrast_agent                VARCHAR2(32)   := @CONTRAST_AGENT;
            v_requested_proc_id             VARCHAR2(32)   := @REQUESTED_PROC_ID;
            v_requested_proc_desc           VARCHAR2(64)   := @REQUESTED_PROC_DESC;
            v_requested_proc_codes          VARCHAR2(256)  := @REQUESTED_PROC_CODES;
            v_requested_proc_priority       VARCHAR2(32)   := @REQUESTED_PROC_PRIORITY;
            v_requested_proc_reason         VARCHAR2(256)  := @REQUESTED_PROC_REASON;        -- 20
            v_requested_proc_comments       VARCHAR2(4000) := @REQUESTED_PROC_COMMENTS;
            v_study_instance_uid            VARCHAR2(64)   := @STUDY_INSTANCE_UID;
            v_proc_placer_order_no          VARCHAR2(32)   := @PROC_PLACER_ORDER_NO;
            v_proc_filler_order_no          VARCHAR2(32)   := @PROC_FILLER_ORDER_NO;
            v_accession_no                  VARCHAR2(32)   := @ACCESSION_NO;
            v_attend_doctor                 VARCHAR2(32)   := @ATTEND_DOCTOR;
            v_perform_doctor                VARCHAR2(32)   := @PERFORM_DOCTOR;
            v_consult_doctor                VARCHAR2(32)   := @CONSULT_DOCTOR;
            v_request_doctor                VARCHAR2(32)   := @REQUEST_DOCTOR;
            v_refer_doctor                  VARCHAR2(32)   := @REFER_DOCTOR;         -- 30
            v_request_department            VARCHAR2(32)   := @REQUEST_DEPARTMENT;
            v_imaging_request_reason        VARCHAR2(64)   := @IMAGING_REQUEST_REASON;
            v_imaging_request_comments      VARCHAR2(4000) := @IMAGING_REQUEST_COMMENTS;
            v_imaging_request_dttm          VARCHAR2(14)   := @IMAGING_REQUEST_DTTM;
            v_isr_placer_order_no           VARCHAR2(32)   := @ISR_PLACER_ORDER_NO;
            v_isr_filler_order_no           VARCHAR2(32)   := @ISR_FILLER_ORDER_NO;
            v_admission_id                  VARCHAR2(32)   := @ADMISSION_ID;
            v_patient_transport             VARCHAR2(32)   := @PATIENT_TRANSPORT;
            v_patient_location              VARCHAR2(32)   := @PATIENT_LOCATION;
            v_patient_residency             VARCHAR2(80)   := @PATIENT_RESIDENCY;         -- 40
            v_patient_name                  VARCHAR2(64)   := @PATIENT_NAME;
            v_patient_id                    VARCHAR2(64)   := @PATIENT_ID;
            v_other_patient_name            VARCHAR2(64)   := @OTHER_PATIENT_NAME;
            v_other_patient_id              VARCHAR2(64)   := @OTHER_PATIENT_ID;
            v_patient_birth_dttm            VARCHAR2(8)    := @PATIENT_BIRTH_DATE;
            v_patient_sex                   CHAR(1)        := @PATIENT_SEX;
            v_patient_weight                VARCHAR2(16)   := @PATIENT_WEIGHT;
            v_patient_size                  VARCHAR2(16)   := @PATIENT_SIZE;
            v_patient_state                 VARCHAR2(256)  := @PATIENT_STATE;
            v_confidentiality               VARCHAR2(256)  := @CONFIDENTIALITY;        -- 50
            v_pregnancy_status              VARCHAR2(256)  := @PREGNANCY_STATUS;
            v_medical_alerts                VARCHAR2(256)  := @MEDICAL_ALERTS;
            v_contrast_allergies            VARCHAR2(256)  := @CONTRAST_ALLERGIES;
            v_special_needs                 VARCHAR2(32)   := @SPECIAL_NEEDS;
            v_specialty                     VARCHAR2(32)   := @SPECIALTY;
            v_diagnosis                     VARCHAR2(2048) := @DIAGNOSIS;
            v_admit_dttm                    VARCHAR2(32)   := @ADMIT_DTTM;
            v_register_dttm                 VARCHAR2(32)   := @REGISTER_DTTM;
            v_study_ssn                     VARCHAR2(64)   := @STUDY_SSN;
            v_insurance_code                VARCHAR2(64)   := @INSURANCE_CODE;         -- 60
            v_emergency                     VARCHAR2(8)    := @EMERGENCY;
            v_special_doctor                VARCHAR2(32)   := @SPECIAL_DOCTOR;         -- 62
            
            v_m_patient_id_issuer           VARCHAR2(32);
            v_m_last_name                   VARCHAR2(32);
            v_m_first_name                  VARCHAR2(32);
            v_m_middle_name                 VARCHAR2(32);
            v_m_prefix                      VARCHAR2(32);
            v_m_suffix                      VARCHAR2(32);
            v_m_race_code                   VARCHAR2(32);
            v_m_account_no                  VARCHAR2(32);         -- 70
            v_m_address                     VARCHAR2(128);
            v_m_order_entry_user_id         VARCHAR2(64);
            v_m_order_entry_location        VARCHAR2(512);
            v_m_order_callback_phone_no     VARCHAR2(512);
            v_m_req_proc_status             VARCHAR2(8);
            v_m_req_proc_code_scheme        VARCHAR2(32);
            v_m_req_proc_code_version       VARCHAR2(32);
            v_m_req_proc_code_meaning       VARCHAR2(256);
            v_m_req_proc_location           VARCHAR2(32);
            v_m_patient_arrange             VARCHAR2(32);         -- 80
            v_m_source_aetitle              VARCHAR2(16);
            v_m_broker_type                 VARCHAR2(16);         -- 82
        
        BEGIN
        
            SP_FILTER.mwl_to_mwl(
                    v_broker_aetitle, 
                    v_order_control_id,
                    v_event_type,
                    v_character_set,
                    v_scheduled_aetitle,
                    v_scheduled_dttm,
                    v_scheduled_modality,
                    v_scheduled_station,
                    v_scheduled_location,
                    v_scheduled_proc_id,        -- 10
                    v_scheduled_proc_desc,
                    v_scheduled_action_codes,
                    v_scheduled_proc_status,
                    v_premedication,
                    v_contrast_agent,
                    v_requested_proc_id,
                    v_requested_proc_desc,
                    v_requested_proc_codes,
                    v_requested_proc_priority,
                    v_requested_proc_reason,    -- 20
                    v_requested_proc_comments,
                    v_study_instance_uid,
                    v_proc_placer_order_no,
                    v_proc_filler_order_no,
                    v_accession_no,
                    v_attend_doctor,
                    v_perform_doctor,
                    v_consult_doctor,
                    v_request_doctor,
                    v_refer_doctor,             -- 30
                    v_request_department,
                    v_imaging_request_reason,
                    v_imaging_request_comments,
                    v_imaging_request_dttm,
                    v_isr_placer_order_no,
                    v_isr_filler_order_no,
                    v_admission_id,
                    v_patient_transport,
                    v_patient_location,
                    v_patient_residency,        -- 40
                    v_patient_name,
                    v_patient_id,
                    v_other_patient_name,
                    v_other_patient_id,
                    v_patient_birth_dttm,
                    v_patient_sex,
                    v_patient_weight,
                    v_patient_size,
                    v_patient_state,
                    v_confidentiality,          -- 50
                    v_pregnancy_status,
                    v_medical_alerts,
                    v_contrast_allergies,
                    v_special_needs,
                    v_specialty,
                    v_diagnosis,
                    v_admit_dttm,
                    v_register_dttm,
                    v_study_ssn,
                    v_insurance_code,           -- 60
                    v_emergency,
                    v_special_doctor,           -- 62
                    
                    v_m_patient_id_issuer,
                    v_m_last_name,
                    v_m_first_name,
                    v_m_middle_name,
                    v_m_prefix,
                    v_m_suffix,
                    v_m_race_code,
                    v_m_account_no,             -- 70
                    v_m_address,
                    v_m_order_entry_user_id, 
                    v_m_order_entry_location, 
                    v_m_order_callback_phone_no, 
                    v_m_req_proc_status,
                    v_m_req_proc_code_scheme,
                    v_m_req_proc_code_version,
                    v_m_req_proc_code_meaning,
                    v_m_req_proc_location,
                    v_m_patient_arrange,        -- 80
                    v_m_source_aetitle,
                    v_m_broker_type             -- 82
                );
            
            v_study_key := SP_MAPPER.put_order(
                    v_event_type,
                    v_order_control_id              ,
                    v_patient_id                    ,
                    v_m_patient_id_issuer           , -- v_patient_id_issuer_code
                    v_patient_name                  ,
                    v_m_last_name                   , -- v_last_name
                    v_m_first_name                  , -- v_first_name
                    v_m_middle_name                 , -- v_middle_name
                    v_m_prefix                      , -- v_prefix
                    v_m_suffix                      , -- v_suffix                -- 10
                    v_patient_birth_dttm            ,
                    v_patient_sex                   ,
                    v_m_race_code                   , -- v_race_code
                    v_confidentiality               ,
                    v_m_account_no                  , -- v_account_no
                    v_m_address                     , -- v_address
                    v_patient_location              ,
                    v_patient_residency             ,
                    v_refer_doctor                  , -- v_refer_doctor_id
                    v_consult_doctor                , -- v_consult_doctor_id    -- 20
                    v_proc_placer_order_no          , -- v_placer_order_id
                    v_proc_filler_order_no          , -- v_filler_order_id
                    v_accession_no                  , -- v_access_no
                    v_scheduled_proc_status         , -- v_order_stat
                    v_imaging_request_reason        , -- v_order_reason 
                    v_imaging_request_comments      , -- v_order_comments
                    v_imaging_request_dttm          , -- v_order_dttm
                    v_request_doctor                , -- v_order_doctor_id
                    v_request_department            , -- v_order_department
                    v_m_order_entry_user_id         , -- v_order_entry_user_id    -- 30
                    v_m_order_entry_location        , -- v_order_entry_location
                    v_m_order_callback_phone_no     , -- v_order_callback_phone_no
                    v_attend_doctor                 , -- v_attend_doctor_id
                    v_perform_doctor                , -- v_perform_doctor_id
                    v_m_req_proc_status             , -- v_reqproc_stat
                    v_requested_proc_id             , -- v_reqproc_id
                    v_requested_proc_desc           , -- v_reqproc_desc
                    v_requested_proc_codes          , -- v_reqproc_code_value
                    v_m_req_proc_code_scheme        , -- v_reqproc_code_scheme
                    v_m_req_proc_code_version       , -- v_reqproc_code_version    -- 40
                    v_m_req_proc_code_meaning       , -- v_reqproc_code_meaning
                    v_study_instance_uid            ,
                    v_requested_proc_reason         , -- v_reqproc_reason
                    v_requested_proc_comments       , -- v_reqproc_comments
                    v_requested_proc_priority       , -- v_reqproc_priority
                    v_m_req_proc_location           , -- v_reqproc_location
                    v_m_patient_arrange             , -- v_patient_arrange
                    v_diagnosis                     ,
                    v_other_patient_id              ,
                    v_other_patient_name            , -- 50
                    v_m_source_aetitle              , -- v_source_aetitle
                    v_broker_aetitle                ,
                    v_m_broker_type                 , -- v_broker_type
                    v_study_ssn                     , -- v_patient_ssn
                    null                            , -- v_diagnosis_code
                    null                            , -- v_diagnosis_code_meaning
                    null                            , -- v_note_and_comments
                    null                            , -- v_sending_facility
                    v_patient_weight                ,
                    v_patient_size                  , -- 60
                    null                            , -- v_vet_sex_neutered
                    null                            , -- v_species_code_description
                    null                            , -- v_breed_code_description
                    null                            , -- v_nk1_name
                    null                            , -- v_nk1_relationship
                    null                              -- v_nk1_organization_name -- 66
                );

            IF v_order_control_id = 'NW' AND v_scheduled_proc_status IN ('120', '110', 'SC') THEN
              v_msps_key := SP_MAPPER.put_msps(
                            v_study_key, -- study_key
                            v_requested_proc_codes, -- reqproc_code_value
                            v_m_req_proc_code_scheme, -- reqproc_code_scheme
                            v_scheduled_proc_id, -- sps_id
                            v_scheduled_modality, -- modality
                            v_scheduled_dttm, -- sps_start_dttm
                            v_scheduled_proc_id, -- protcode_value
                            v_scheduled_action_codes, -- protcode_scheme
                            v_scheduled_proc_desc, -- protcode_meaning
                            1, -- index
                            v_scheduled_aetitle, -- aetitle
                            v_scheduled_location, -- scheduled_location
