            v_report_stat := NVL(v_report_stat, 'F');
    
            INSERT INTO report_ris (patient_id, accession_no, study_instance_uid, report_stat, creator_id, creator_name, create_dttm, dictator_id, dictator_name, dictate_dttm, transcriber_id, transcriber_name, transcribe_dttm, approver_id, approver_name, approve_dttm, reviser_id, reviser_name, revise_dttm, report_type, report_text, conclusion, study_dttm, scheduled_location, perform_department, perform_modality, request_dttm, request_name, request_code, request_doctor, perform_doctor, refer_doctor, scheduled_dttm, patient_name, patient_sex, patient_birth_dttm, admission_id, study_comments, study_reason, attend_doctor)
                VALUES (@PATIENT_ID, @ACCESS_NO, @STUDY_INSTANCE_UID, v_report_stat, @CREATE_USERID, @CREATE_USERNAME, @CREATE_DTTM, @DICTATE_USERID, @DICTATE_USERNAME, @DICTATE_DTTM, @TRANSCRIBE_USERID, @TRANCRIBE_USERNAME, @TRANSCRIBE_DTTM, @APPROVE_USERID, @APPROVE_USERNAME, @APPROVE_DTTM, @REVISE_USERID, @REVISE_USERNAME, @REVISE_DTTM, @REPORT_TYPE, @REPORT_TEXT, @CONCLUSION, @STUDY_DTTM, @INSTITUTION, @DEPARTMENT, @MODALITIES, @REQUEST_DTTM, @REQUEST_NAME, @REQUEST_CODE, @REQUEST_DOCTOR, @PERFORM_DOCTOR, @REFER_DOCTOR, @SPS_START_DTTM, @PATIENT_NAME, @PATIENT_SEX, @PATIENT_BIRTH_DTTM, @SPS_ID, @STUDY_COMMENTS, @STUDY_REASON, @OPERATORS);
        END;
